#!/usr/bin/env python3
from pwn import *
import time
context.log_level='error'
HOST='pwn.chal.csaw.io'; PORT=8000

def conn():
    for _ in range(10):
        try:
            return remote(HOST,PORT,timeout=2)
        except Exception:
            time.sleep(0.5)
    raise SystemExit('connect failed')

def probe(seq, recv_time=1.0):
    io=conn()
    for s in seq:
        io.sendline(s)
        time.sleep(0.05)
    data=b''
    closed=False
    t=time.time()
    while time.time()-t<recv_time:
        try:
            chunk=io.recv(timeout=0.2)
            if chunk==b'':
                closed=True
                break
            data+=chunk
        except EOFError:
            closed=True
            break
        except Exception:
            pass
    try: io.close()
    except: pass
    return closed,data

def main():
    tests=[[b'1'],[b'2'],[b'3'],[b'0'],[b'999'],[b'1',b'A'],[b'1',b''],[b'2',b'BBBB']]
    for t in tests:
        closed,data=probe(t)
        print(t,'closed',closed,'len',len(data),'data',repr(data))

if __name__=='__main__':
    main()

#!/usr/bin/env python3
from pwn import *
import time
context.log_level='info'
HOST='172.19.0.2'
PORT=8000

def conn():
    for _ in range(10):
        try:
            return remote(HOST,PORT,timeout=3)
        except Exception as e:
            log.warning(f'connect fail {e}')
            time.sleep(0.5)
    raise SystemExit('connect failed')

def interact_case(lines, wait_after=0.5, read_time=1.5):
    io=conn()
    out=b''
    # read initial
    try:
        out += io.recv(timeout=0.6)
    except Exception:
        pass
    for ln in lines:
        if ln is None:
            # send empty line
            io.sendline(b'')
        else:
            io.sendline(ln)
        time.sleep(wait_after)
        # drain
        t=time.time()
        while time.time()-t<read_time:
            try:
                chunk=io.recv(timeout=0.2)
                if chunk==b'':
                    break
                out += chunk
            except EOFError:
                break
            except Exception:
                pass
    # final drain
    t=time.time()
    while time.time()-t<0.5:
        try:
            chunk=io.recv(timeout=0.2)
            if chunk==b'':
                break
            out += chunk
        except Exception:
            break
    closed=False
    try:
        io.sendline(b'')
        time.sleep(0.1)
        io.recv(timeout=0.1)
    except EOFError:
        closed=True
    except Exception:
        pass
    io.close()
    return out,closed

def main():
    cases={
        'just-connect':[],
        'opt1':[b'1'],
        'opt2':[b'2'],
        'opt1_len0':[b'1',None],
        'opt1_len1':[b'1',b'A'],
        'opt1_len7':[b'1',b'A'*7],
        'opt1_len8':[b'1',b'A'*8],
        'opt1_len9':[b'1',b'A'*9],
        'opt1_32':[b'1',b'A'*32],
        'opt1_64':[b'1',b'A'*64],
        'opt2_then0':[b'2',None],
        'opt2_len1':[b'2',b'B'],
        'opt2_len8':[b'2',b'B'*8],
        'opt2_64':[b'2',b'B'*64],
        'weird':[b'3'],
        'zero':[b'0'],
    }
    for name,lines in cases.items():
        log.info(f'=== case {name} lines={lines} ===')
        out,closed=interact_case(lines)
        print('CLOSED?',closed)
        print(hexdump(out))
        print(out.decode('latin-1',errors='replace'))
        print('====')
        time.sleep(0.2)

if __name__=='__main__':
    main()

import socket
for host in ['pwn.chal.csaw.io','172.19.0.2','localhost','127.0.0.1']:
  s=socket.socket(); s.settimeout(2)
  try:
    s.connect((host,8000))
    print('connected',host)
    print(s.recv(2000))
  except Exception as e:
    print('fail',host,e)
  finally:
    try: s.close()
    except: pass

